((SELECT id FROM sys_user WHERE email = 'jobs@heyuelife.com'), 'DEMO20260408031', '门店运营经理', '连锁运营', '上海', 15000, 22000, '3年', '大专', 2, '负责连锁餐饮门店经营目标、服务标准和营运流程优化，持续推进巡店、营业分析、人员排班和服务质量提升，联动区域督导、供应链、培训和店长完成问题闭环与数据复盘。要求具备连锁运营经验，熟悉门店运营，具备餐饮连锁管理经验者优先。', '["五险一金","绩效奖金","员工餐","带薪年假","节日福利","晋升通道"]', '["门店运营","餐饮连锁管理"]', 'PUBLISHED', '2026-04-01 11:00:00', '2026-06-30 23:59:00', '2026-04-01 11:00:00', '2026-04-01 11:00:00'),
